// 後端做的事：收到請求 → 找對的處理邏輯 → 回傳結果
function backend(request) {
  const { method, path } = request;        // 1. 看打哪個網址、什麼方法
  if (method === "GET" && path === "/users") {  // 2. 路由：交給對的處理
    return { status: 200, body: ["Nami", "Luffy"] };
  }
  return { status: 404, body: "Not Found" };   // 3. 找不到 → 404
}

console.log(backend({ method: "GET", path: "/users" }));
console.log(backend({ method: "GET", path: "/unknown" }));

// HTTP 的兩個核心：method（想做什麼）+ status code（結果如何）
const methods = { GET: "拿資料", POST: "新增", PUT: "整筆更新", DELETE: "刪除" };
const status = { "200": "成功", "201": "已建立", "404": "找不到", "500": "伺服器爆了" };

for (const [m, d] of Object.entries(methods)) console.log(m + " → " + d);
console.log("---");
for (const [code, d] of Object.entries(status)) console.log(code + " → " + d);

const user = { id: 1, name: "Nami", email: "n@x.com", age: 20, bio: "海賊" };

// REST：固定回傳整包（常常多給你用不到的）
function rest() { return user; }

// GraphQL：客戶端指定要哪些欄位，不多給
function graphql(fields) {
  const r = {};
  for (const f of fields) r[f] = user[f];
  return r;
}

console.log("REST 給你整包：", rest());
console.log("GraphQL 只給你要的：", graphql(["name", "email"]));

// 單體（Monolith）：所有功能在同一個程式裡、一起部署
const monolith = { 包含: ["登入", "下單", "金流", "通知"], 部署: "全部一起" };

// 微服務（Microservice）：拆成各自獨立、可分開部署 / 擴充
const microservices = {
  登入服務: "獨立部署，自己壞掉不拖累別人",
  金流服務: "流量大時只加開這一個就好",
};

console.log("單體：", monolith);
console.log("微服務：", microservices);

// 後端語言很多，但做的事都一樣：收請求 → 回資料
const langs = {
  "Node.js": "JS 全端、生態大、最好上手",
  "Python": "AI / 資料分析首選、語法簡單",
  "Go": "高併發、雲端基礎設施愛用",
  "Rust": "極致效能與安全、學習較陡",
  "PHP": "WordPress / 老牌、接案機會多",
};
for (const [name, pos] of Object.entries(langs)) {
  console.log(name + "：" + pos);
}

